{"content": "#!/usr/bin/env python3
"""
Paper Trading Quick Command
Usage: python quick.py <command> [args]

Commands:
  price               - Show current XAU/USDT price
  analysis            - Full market analysis
  open <side> [price] - Open trade (LONG/SHORT)
  close <id> [price]  - Close trade by ID
  status              - Show open trades + PnL
  stats               - Show statistics
  reset [balance]     - Reset account
"""
import sys
import os
sys.path.insert(0, os.path.dirname(__file__))

from engine import PaperTradingEngine
from config import *

engine = PaperTradingEngine()

def cmd_price():
    price = engine.get_price()
    if price:
        print(f"💰 XAU/USDT: ${price:,.2f}")
    else:
        print("❌ Cannot get price")

def cmd_analysis():
    a = engine.analyze_market()
    if not a:
        print("❌ Cannot analyze")
        return

    print(f"""
📊 XAU/USDT ANALYSIS
═══════════════════════════════════
  💰 Price:      ${a['price']:,.2f}
  📈 VWAP:       ${a['vwap']:,.2f} ({a['vwap_signal']})
  📊 RSI:        {a['rsi']}
  🔼 Trend:      {a['trend']}
  📉 Support:    ${a['support']:,.2f}
  📈 Resistance: ${a['resistance']:,.2f}
═══════════════════════════════════""")

    # Quick signal
    if a['rsi'] < 30 and a['vwap_signal'] == 'BELOW':
        print("  🟢 SIGNAL: Potential LONG (RSI oversold + below VWAP)")
    elif a['rsi'] > 70 and a['vwap_signal'] == 'ABOVE':
        print("  🔴 SIGNAL: Potential SHORT (RSI overbought + above VWAP)")
    else:
        print("  ⚪ SIGNAL: WAIT — No clear entry")

def cmd_status():
    price = engine.get_price()
    open_trades = engine.get_open_trades()

    print(f"\n📂 OPEN TRADES — Balance: ${engine.balance:,.2f}")
    print("═" * 55)

    if not open_trades:
        print("  📭 No open trades")
        return

    for t in open_trades:
        if price:
            if t['side'] == 'LONG':
                pnl = (price - t['entry_price']) * t['quantity']
                pct = ((price - t['entry_price']) / t['entry_price'] * 100)
            else:
                pnl = (t['entry_price'] - price) * t['quantity']
                pct = ((t['entry_price'] - price) / t['entry_price'] * 100)

            emoji = '🟢' if pnl > 0 else '🔴'
            print(f"  {emoji} #{t['id']} {t['side']} {t['quantity']:.4f} @ ${t['entry_price']:,.2f}")
            print(f"     Current: ${price:,.2f} | PnL: ${pnl:+,.2f} ({pct:+.2f}%)")
            print(f"     SL: ${t['stop_loss']:,.2f} | TP: ${t['take_profit']:,.2f}")

    print("═" * 55)

def cmd_stats():
    s = engine.get_stats()
    print(f"""
📊 STATISTICS
═══════════════════════════════════
  Balance:     ${s['balance']:,.2f} ({s['total_return']:+.1f}%)
  Trades:      {s['total_trades']} (W:{s['wins']} L:{s['losses']})
  Win Rate:    {s['win_rate']:.1f}%
  Total PnL:   ${s['total_pnl']:+,.2f}
  Avg PnL:     ${s['avg_pnl']:+,.2f}
  Best:        ${s['best_trade']:+,.2f}
  Worst:       ${s['worst_trade']:+,.2f}
  Profit Fact: {s['profit_factor']:.2f}
═══════════════════════════════════""")

def cmd_quick_open(side, price_override=None):
    """Quick open with auto SL/TP"""
    a = engine.analyze_market()
    if not a:
        print("❌ Cannot analyze market")
        return

    price = float(price_override) if price_override else a['price']

    if side == 'LONG':
        sl = a['support'] - 2
        tp = a['resistance'] - 2
    else:
        sl = a['resistance'] + 2
        tp = a['support'] + 2

    qty = engine.calculate_position_size(price, sl)
    margin = (price * qty) / engine.leverage

    print(f"\n⚡ QUICK {side}")
    print(f"  Entry: ${price:,.2f}")
    print(f"  SL: ${sl:,.2f} | TP: ${tp:,.2f}")
    print(f"  Size: {qty:.4f} | Margin: ${margin:.2f}")

    confirm = input("  Confirm? [y/N]: ")
    if confirm.lower() == 'y':
        result = engine.open_trade('XAUUSDT', side, price, qty, sl, tp, f'Quick {side}')
        if 'error' in result:
            print(f"  ❌ {result['error']}")
        else:
            print(f"  ✅ OPENED! #{result['id']} Balance: ${result['balance_after']:,.2f}")

# Main
if __name__ == '__main__':
    args = sys.argv[1:]

    if not args:
        print(__doc__)
        sys.exit(0)

    cmd = args[0].lower()

    if cmd == 'price':
        cmd_price()
    elif cmd in ['analysis', 'analyze', 'a']:
        cmd_analysis()
    elif cmd in ['open', 'o']:
        if len(args) < 2:
            print("Usage: python quick.py open <LONG|SHORT> [price]")
            sys.exit(1)
        side = args[1].upper()
        price = args[2] if len(args) > 2 else None
        cmd_quick_open(side, price)
    elif cmd in ['close', 'c']:
        if len(args) < 2:
            print("Usage: python quick.py close <trade_id> [price]")
            sys.exit(1)
        trade_id = int(args[1])
        price = float(args[2]) if len(args) > 2 else engine.get_price()
        lesson = ' '.join(args[3:]) if len(args) > 3 else ''
        result = engine.close_trade(trade_id, price, lesson)
        if 'error' in result:
            print(f"❌ {result['error']}")
        else:
            emoji = '🟢' if result['net_pnl'] > 0 else '🔴'
            print(f"{emoji} Closed #{trade_id} | PnL: ${result['net_pnl']:+,.2f} [{result['status']}]")
    elif cmd in ['status', 's']:
        cmd_status()
    elif cmd in ['stats', 'st']:
        cmd_stats()
    elif cmd in ['reset', 'r']:
        bal = float(args[1]) if len(args) > 1 else INITIAL_BALANCE
        result = engine.reset(bal)
        print(f"✅ {result['message']}")
    elif cmd in ['check', 'ck']:
        from cli import cmd_check_sl_tp
        cmd_check_sl_tp(engine)
    else:
        print(f"Unknown command: {cmd}")
        print(__doc__)
", "path": "paper_trading/quick.py"}

