{"content": "#!/usr/bin/env python3
"""
Paper Trading Bot — Auto Monitor
Jalan background, cek signal tiap menit, log ke file
"""
import sys, os, time, json
sys.path.insert(0, os.path.dirname(__file__))

from engine import PaperTradingEngine
from datetime import datetime

engine = PaperTradingEngine()
LOG_FILE = os.path.expanduser('~/paper_trading_log.txt')

def log(msg):
    ts = datetime.now().strftime('%H:%M:%S')
    line = f"[{ts}] {msg}"
    print(line)
    with open(LOG_FILE, 'a') as f:
        f.write(line + '\n')

def check_and_signal():
    """Check market + open trades"""
    a = engine.analyze_market()
    price = engine.get_price()

    if not a or not price:
        return

    # Check open trades SL/TP
    open_trades = engine.get_open_trades()
    for t in open_trades:
        hit = None
        if t['side'] == 'LONG':
            if t['stop_loss'] and price <= t['stop_loss']:
                hit = 'SL'
            elif t['take_profit'] and price >= t['take_profit']:
                hit = 'TP'
        else:
            if t['stop_loss'] and price >= t['stop_loss']:
                hit = 'SL'
            elif t['take_profit'] and price <= t['take_profit']:
                hit = 'TP'

        if hit:
            exit_p = t['stop_loss'] if hit == 'SL' else t['take_profit']
            result = engine.close_trade(t['id'], exit_p, f"Auto {hit} monitor")
            emoji = '🔴' if hit == 'SL' else '🟢'
            log(f"{emoji} AUTO {hit}! #{t['id']} {t['side']} @ ${exit_p:,.2f} | PnL: ${result['net_pnl']:+,.2f}")

    # Generate signal
    signals = []
    if a['rsi'] < 30:
        signals.append('OVERSOLD')
    elif a['rsi'] > 70:
        signals.append('OVERBOUGHT')

    if a['vwap_signal'] == 'BELOW' and a['rsi'] < 35:
        signals.append('LONG_BOUNCE')
    elif a['vwap_signal'] == 'ABOVE' and a['rsi'] > 65:
        signals.append('SHORT_REJECT')

    signal_str = ', '.join(signals) if signals else 'NO_SIGNAL'

    # Floating PnL
    floating = 0
    for t in open_trades:
        if t['side'] == 'LONG':
            floating += (price - t['entry_price']) * t['quantity']
        else:
            floating += (t['entry_price'] - price) * t['quantity']

    log(f"XAU ${price:,.2f} | VWAP ${a['vwap']:,.2f}({a['vwap_signal']}) | RSI {a['rsi']} | {a['trend']} | {signal_str} | Balance: ${engine.balance:,.2f} | Float: ${floating:+,.2f} | Open: {len(open_trades)}")

    return signal_str

def main():
    log("=" * 50)
    log("PAPER TRADING BOT — MONITOR STARTED")
    log("=" * 50)

    # Initial status
    stats = engine.get_stats()
    log(f"Balance: ${stats['balance']:,.2f} | Trades: {stats['total_trades']} | WR: {stats['win_rate']}%")

    while True:
        try:
            check_and_signal()
        except Exception as e:
            log(f"ERROR: {e}")

        time.sleep(60)  # Check every 1 minute

if __name__ == '__main__':
    main()
